// @grant       GM_setValue
// @grant       GM_getValue
// @version     1.1
// @author      piquecc
// @description Roobet larp script
// ==/UserScript==

(function () {
    'use strict';

    const RANKS = [
        { name: "Beginner", min: 0, max: 999.99 },
        { name: "Silver I", min: 1000, max: 2699.99 },
        { name: "Silver II", min: 2700, max: 5499.99 },
        { name: "Silver III", min: 5500, max: 9999.99 },
        { name: "Silver IV", min: 10000, max: 18499.99 },
        { name: "Gold I", min: 18500, max: 31999.99 },
        { name: "Gold II", min: 32000, max: 55999.99 },
        { name: "Gold III", min: 56000, max: 94999.99 },
        { name: "Gold IV", min: 95000, max: 159999.99 },
        { name: "Emerald I", min: 160000, max: 274999.99 },
        { name: "Emerald II", min: 275000, max: 459999.99 },
        { name: "Emerald III", min: 460000, max: 784999.99 },
        { name: "Ruby I", min: 785000, max: 1299999.99 },
        { name: "Ruby II", min: 1300000, max: 2249999.99 },
        { name: "Ruby III", min: 2250000, max: 3799999.99 },
        { name: "Diamond I", min: 3800000, max: 6499999.99 },
        { name: "Diamond II", min: 6500000, max: 9999999.99 },
        { name: "Diamond III", min: 10000000, max: 17999999.99 },
        { name: "Champion I", min: 18000000, max: 29999999.99 },
        { name: "Champion II", min: 30000000, max: 49999999.99 },
        { name: "Champion III", min: 50000000, max: 87999999.99 },
        { name: "Legend I", min: 88000000, max: 149999999.99 },
        { name: "Legend II", min: 150000000, max: 249999999.99 },
        { name: "Legend III", min: 250000000, max: 424999999.99 },
        { name: "Master I", min: 425000000, max: 719999999.99 },
        { name: "Master II", min: 720000000, max: 1199999999.99 },
        { name: "Master III", min: 1200000000, max: 1999999999.99 },
        { name: "Grandmaster I", min: 2000000000, max: 3499999999.99 },
        { name: "Grandmaster II", min: 3500000000, max: 5999999999.99 },
        { name: "Grandmaster III", min: 6000000000, max: 9999999999.99 },
        { name: "Immortal", min: 10000000000, max: Infinity }
    ];

    const CDN = 'cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/';
    const RANK_IMAGES = {
        3: `${CDN}BpYHoPhv.png`,
        4: `${CDN}o4qQ3nvM.png`,
        23: `${CDN}CSiML-CW.png`,
        28: `${CDN}D1l35eAe.png`,
        29: `${CDN}7PRrMH8y.png`,
        30: `${CDN}Dt8aTCi5.png`,
    };

    function rankToImage(r) {
        let ret = RANK_IMAGES[r] || '';
        if (ret == '') {
            switch (rank) {
                case 0:
                    return String.raw`data:image/png;base64,`;
                case 1:
                    return String.raw`data:image/png;base64,`;
                case 2:
                    return String.raw`data:image/png;base64,`;
                case 3:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/BpYHoPhv.png";
                case 4:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/o4qQ3nvM.png";
                case 5:
                    return String.raw`data:image/png;base64,`;
                case 6:
                    return String.raw`data:image/png;base64,`;
                case 7:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/DAPIIVJW.png";
                case 8:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/CkPiaIfD.png";
                case 9:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/DfZM67CD.png";
                case 10:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/D-R-nRxi.png";
                case 11:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/Cz0id5eX.png";
                case 12:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/ovnwCuDs.png";
                case 13:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/_FBDShfK.png";
                case 14:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/BeCgV2VZ.png";
                case 15:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/C_20QMG5.png";
                case 16:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/M78YjSMK.png";
                case 17:
                    return String.raw`data:image/png;base64,`;
                case 18:
                    return String.raw`data:image/png;base64,`;
                case 19:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/0CaSnJ73.png";
                case 20:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/0CaSnJ73.png";
                case 21:
                    return String.raw`data:image/png;base64,`;
                case 22:
                    return String.raw`data:image/png;base64,`;
                case 23:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/CSiML-CW.png";
                case 24:
                    return String.raw`data:image/png;base64,`;
                case 25:
                    return String.raw`data:image/png;base64,`;
                case 26:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/DK8_vd-z.png";
                case 27:
                    return String.raw`data:image/png;base64,`;
                case 28:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/D1l35eAe.png";
                case 29:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/7PRrMH8y.png";
                case 30:
                    return "cdn-cgi/image/dpr=2.0,width=48.768,height=26.67,quality=85,format=auto/assets/Dt8aTCi5.png";
            }
        }
        return RANK_IMAGES[r] || '';
    }

    let balance = GM_getValue('balance', '0.00');
    let wagered = GM_getValue('wagered', 0);
    let bets = GM_getValue('bets', 0);
    let tip = GM_getValue('tip', 0);
    let rank = GM_getValue('rank', 0);

    function saveState() {
        GM_setValue('balance', balance);
        GM_setValue('wagered', wagered);
        GM_setValue('bets', bets);
        GM_setValue('tip', tip);
        GM_setValue('rank', rank);
    }

    const SEL = {
        stats: 'h5.MuiTypography-root.MuiTypography-display_sm.css-1yii6q3',
        progressBar: '.MuiLinearProgress-bar1Determinate',
        nextRank: 'span.MuiTypography-root.MuiTypography-text_s.css-x17ll9',
        rankImg1: 'img.MuiBox-root.css-ws1l4a',
        rankImg2: 'img.MuiBox-root.css-pik4km',
        balanceText: 'p.MuiTypography-root.MuiTypography-body1.css-1bmkrmt',
    };

    function hook() {
        const stats = document.querySelectorAll(SEL.stats);
        const avg = bets > 0 ? wagered / bets : 0;

        if (stats[0]) stats[0].textContent = RANKS[rank].name;
        if (stats[2]) stats[2].textContent = `$${wagered.toFixed(2)}`;
        if (stats[3]) stats[3].textContent = Math.floor(bets);
        if (stats[4]) stats[4].textContent = `$${avg.toFixed(2)}`;
        if (stats[5]) stats[5].textContent = `$${tip.toFixed(2)}`;

        const { min, max } = RANKS[rank];
        let progress = ((wagered - min) / (max - min)) * 100;
        progress = Math.max(0, Math.min(100, progress));

        document.querySelectorAll(SEL.progressBar).forEach(bar => {
            bar.style.setProperty('transform', `translateX(-${progress}%)`, 'important');
        });

        if (rank + 1 < RANKS.length) {
            document.querySelectorAll(SEL.nextRank).forEach(el => {
                el.textContent = `$${(RANKS[rank + 1].min - wagered).toFixed(2)}`;
            });
        }

        const imgSrc = rankToImage(rank);
        if (imgSrc) {
            document.querySelectorAll(SEL.rankImg1).forEach(img => { img.src = imgSrc; });
            document.querySelectorAll(SEL.rankImg2).forEach(img => { img.src = imgSrc; });
        }

        document.querySelectorAll(SEL.balanceText).forEach(el => {
            el.textContent = `$${balance}`;
        });
    }

    let timeout;
    const debouncedHook = () => {
        clearTimeout(timeout);
        timeout = setTimeout(hook, 500);
    };

    const observer = new MutationObserver(debouncedHook);
    observer.observe(document.body, { childList: true, subtree: true });

    let popup = null;

    function closePopup() {
        if (!popup) return;
        popup.style.transition = 'all 200ms ease';
        popup.style.opacity = '0';
        popup.style.transform = 'translate(-50%, -50%) scale(0.95)';
        setTimeout(() => {
            if (popup) popup.remove();
            popup = null;
        }, 200);
    }

    function createPopup() {
        if (popup) { closePopup(); return; }

        popup = document.createElement('div');
        popup.className = 'cashier-popup';
        popup.style.cssText = `
            position: fixed; top: 50%; left: 50%;
            transform: translate(-50%, -50%) scale(0.95);
            opacity: 0; width: 420px;
            background: linear-gradient(180deg, #1e1433, #2a1f4a);
            border: 5px solid #090c1d; border-radius: 16px;
            box-shadow: 0 0 40px rgba(0,0,0,1);
            z-index: 2147483647; color: white; overflow: hidden;
            transition: all 280ms cubic-bezier(0.34, 1.56, 0.64, 1);
        `;

        popup.innerHTML = `
            <!-- Header -->
            <div style="padding:16px 20px; background:#090c1d; display:flex; align-items:center; justify-content:space-between;">
                <div style="font-size:20px; font-weight:700;">roobetlarp.gg</div>
                <div id="larp-close" style="cursor:pointer; font-size:28px; line-height:20px; opacity:0.7;">×</div>
            </div>

            <!-- Tabs -->
            <div id="larp-tabs" style="display:flex; background:#090c1d;">
                <div data-tab="deposit" style="flex:1; text-align:center; padding:14px; border-bottom:1px solid #3a2a66; color:white; font-weight:600; cursor:pointer;">Deposit</div>
                <div data-tab="profile" style="flex:1; text-align:center; padding:14px; color:#bbb; cursor:pointer;">Profile</div>
            </div>

            <!-- Content -->
            <div id="larp-tab-content" style="padding:20px; min-height:340px;">
                <!-- Deposit -->
                <div id="larp-content-deposit">
                    <div style="margin-bottom:24px;">
                        <label style="display:block; margin-bottom:8px; font-size:15px; color:#ddd;">Amount to deposit</label>
                        <div style="position:relative;">
                            <input id="larp-deposit-amount" type="text" placeholder="0.00"
                                   style="width:100%; background:#1a102f; border:none; border-radius:12px; padding:18px 20px; font-size:28px; font-weight:400; color:white; outline:none;">
                            <div style="position:absolute; right:20px; top:50%; transform:translateY(-50%); font-size:22px; font-weight:600; color:#bbb;">$</div>
                        </div>
                        <div style="margin-top:8px; font-size:13px; color:#bbb; display:flex; gap:8px; flex-wrap:wrap;">
                            <span data-quick-deposit="0.1" style="background:#3a2a66; padding:4px 12px; border-radius:9999px; cursor:pointer;">0.1</span>
                            <span data-quick-deposit="0.5" style="background:#3a2a66; padding:4px 12px; border-radius:9999px; cursor:pointer;">0.5</span>
                            <span data-quick-deposit="1"   style="background:#3a2a66; padding:4px 12px; border-radius:9999px; cursor:pointer;">1</span>
                            <span data-quick-deposit="5"   style="background:#3a2a66; padding:4px 12px; border-radius:9999px; cursor:pointer;">5</span>
                            <span data-quick-deposit="10"  style="background:#3a2a66; padding:4px 12px; border-radius:9999px; cursor:pointer;">10</span>
                        </div>
                    </div>
                    <div style="background:#261d42; border-radius:12px; padding:16px; margin-bottom:20px;">
                        <button id="larp-deposit-btn" style="width:100%; background:#6b4eff; color:white; border:none; padding:14px; border-radius:12px; font-weight:600; cursor:pointer;">Deposit</button>
                    </div>
                    <div style="text-align:center; margin-top:16px; font-size:13px; color:#888;">
                        <a style="color:#888" href="https://discord.gg/roobet">Having trouble larping?</a>
                    </div>
                </div>

                <!-- Profile -->
                <div id="larp-content-profile" style="display:none; text-align:center; color:#ddd;">
                    <div style="margin-bottom:5px;">
                        <label style="display:block; margin-bottom:5px; font-size:15px; color:#ddd;">Rank</label>
                        <select id="larp-rank" style="font-weight:400; width:100%; background:#1a102f; border:none; border-radius:12px; padding:12px 14px; color:white; outline:none;"></select>
                    </div>
                    <label style="display:block; margin-bottom:5px; font-size:15px; color:#ddd;">Total Bets</label>
                    <input id="larp-total-bets" type="text" placeholder="0"
                           style="width:100%; background:#1a102f; border:none; border-radius:12px; padding:12px 14px; font-size:15px; color:white; outline:none; margin-bottom:8px;">
                    <label style="display:block; margin-bottom:5px; font-size:15px; color:#ddd;">Wagered</label>
                    <div style="position:relative; margin-bottom:8px;">
                        <input id="larp-amount-wagered" type="text" placeholder="0.00"
                               style="width:100%; background:#1a102f; border:none; border-radius:12px; padding:12px 14px; font-size:15px; color:white; outline:none;">
                        <div style="position:absolute; right:20px; top:50%; transform:translateY(-50%); font-size:15px; font-weight:600; color:#bbb;">$</div>
                    </div>
                    <label style="display:block; margin-bottom:5px; font-size:15px; color:#ddd;">Total Tipped</label>
                    <div style="position:relative; margin-bottom:8px;">
                        <input id="larp-total-tipped" type="text" placeholder="0.00"
                               style="width:100%; background:#1a102f; border:none; border-radius:12px; padding:12px 14px; font-size:15px; color:white; outline:none;">
                        <div style="position:absolute; right:20px; top:50%; transform:translateY(-50%); font-size:15px; font-weight:600; color:#bbb;">$</div>
                    </div>
                    <div style="background:#261d42; border-radius:12px; padding:16px; margin-bottom:20px;">
                        <button id="larp-save-btn" style="width:100%; background:#6b4eff; color:white; border:none; padding:14px; border-radius:12px; font-weight:600; cursor:pointer;">Save</button>
                    </div>
                </div>
            </div>
        `;

        document.body.appendChild(popup);

        const select = popup.querySelector('#larp-rank');
        RANKS.forEach((item, i) => {
            const opt = document.createElement('option');
            opt.value = i;
            opt.textContent = `${item.name} (${item.min.toLocaleString()}–${item.max === Infinity ? '∞' : item.max.toLocaleString()})`;
            select.appendChild(opt);
        });
        select.value = rank;

        popup.querySelector('#larp-total-bets').value = bets || '';
        popup.querySelector('#larp-amount-wagered').value = wagered || '';
        popup.querySelector('#larp-total-tipped').value = tip || '';

        popup.querySelector('#larp-close').addEventListener('click', closePopup);

        popup.querySelectorAll('#larp-tabs > div').forEach(tab => {
            tab.addEventListener('click', () => {
                const tabName = tab.dataset.tab;
                popup.querySelectorAll('#larp-tab-content > div').forEach(d => d.style.display = 'none');
                const content = popup.querySelector(`#larp-content-${tabName}`);
                if (content) content.style.display = 'block';

                popup.querySelectorAll('#larp-tabs > div').forEach(t => {
                    if (t.dataset.tab === tabName) {
                        t.style.borderBottom = '1px solid #3a2a66';
                        t.style.color = 'white';
                        t.style.fontWeight = '600';
                    } else {
                        t.style.borderBottom = '';
                        t.style.color = '#bbb';
                        t.style.fontWeight = '400';
                    }
                });
            });
        });

        popup.querySelectorAll('[data-quick-deposit]').forEach(btn => {
            btn.addEventListener('click', () => {
                popup.querySelector('#larp-deposit-amount').value = btn.dataset.quickDeposit;
            });
        });

        popup.querySelector('#larp-deposit-btn').addEventListener('click', () => {
            const amount = popup.querySelector('#larp-deposit-amount').value || '0';
            balance = amount;
            GM_setValue('balance', balance);
        });

        select.addEventListener('change', () => {
            rank = parseInt(select.value, 10);
            saveState();
        });

        popup.querySelector('#larp-save-btn').addEventListener('click', () => {
            bets = parseFloat(popup.querySelector('#larp-total-bets')?.value || '0');
            wagered = parseFloat(popup.querySelector('#larp-amount-wagered')?.value || '0');
            tip = parseFloat(popup.querySelector('#larp-total-tipped')?.value || '0');
            saveState();
            hook();
        });

        popup.addEventListener('keydown', e => e.stopImmediatePropagation(), true);
        popup.addEventListener('keyup', e => e.stopImmediatePropagation(), true);

        popup.addEventListener('click', e => { if (e.target === popup) closePopup(); });

        requestAnimationFrame(() => {
            popup.style.opacity = '1';
            popup.style.transform = 'translate(-50%, -50%) scale(1)';
        });

        setTimeout(() => {
            const input = popup.querySelector('#larp-deposit-amount');
            if (input) input.focus();
        }, 300);
    }

    document.addEventListener('keydown', e => {
        if (e.ctrlKey && e.key.toLowerCase() === 'a') {
            e.preventDefault();
            e.stopImmediatePropagation();
            createPopup();
        }
        if (e.key === 'Escape' && popup) {
            closePopup();
        }
    });
})();